window.__DB_ARTICLES["d3b9cdd31bbe16fd"] = {"title": "View from The Hill: Ed Husic stirs the pot on AUKUS as Peter Garrett to lead public inquiry", "byline": "Michelle Grattan", "source": "The Conversation", "url": "https://theconversation.com/view-from-the-hill-ed-husic-stirs-pot-on-aukus-as-peter-garrett-to-lead-public-inquiry-284301", "body": "<p>Labor backbencher Ed Husic has reopened internal tensions over AUKUS, asking in parliament whether the party&rsquo;s earlier resolution of support still holds given changes to the submarine arrangements, and arguing Australia &lsquo;won&rsquo;t get the deal that was promised.&rsquo; The government has appointed former minister Peter Garrett to lead a public inquiry into the pact — a move Grattan suggests could become one of its biggest headaches, landing just as Labor&rsquo;s national conference looms in July. The episode exposes sovereignty concerns and factional management challenges within Labor&rsquo;s own ranks.</p>", "partial": true};
